To define a custom particle class with mass and velocity attributes on top of `ParticleBase`, you need to derive from `ParticleBase` and add `ParticleAttribute` instances for mass and velocity. You should also use the constructor to initialize these attributes by calling `addAttribute`.

Here is an example:

```cpp
#include "Particle/ParticleBase.h"
#include "Particle/ParticleAttrib.h"

class CustomParticles : public ParticleBase<ParticleSpatialLayout<double, 3>> {
public:
    // Attributes for this class
    ParticleAttribute<double> mass; // mass attribute
    particle_position_type vel;     // velocity attribute

    // Constructor: add attributes to base class
    CustomParticles(ParticleSpatialLayout<double, 3>* L) : ParticleBase(L) {
        addAttribute(mass);
        addAttribute(vel);
    }
};
```

